    def validate_workspace(workspace: str, language: str) -> Tuple[bool, str]:
        """Validate workspace exists and contains required files."""
        workspace_path = Path(workspace)

        # Check directory exists
        if not workspace_path.exists():
            return False, f"Workspace '{workspace}' does not exist"

        if not workspace_path.is_dir():
            return False, f"Workspace '{workspace}' is not a directory"

