package main

import (
	"flag"
	"os"

	"github.com/volcano-sh/agentcube/pkg/router"
	"k8s.io/klog/v2"
)

func main() {
	var (
		port               = flag.Int("port", 8080, "Server port")
		workloadManagerURL = flag.String("workload-manager-url", os.Getenv("WORKLOAD_MANAGER_URL"), "Workload manager URL")
		enableAuth         = flag.Bool("enable-auth", true, "Enable authentication")
		maxConcurrent      = flag.Int("max-concurrent", 1000, "Maximum concurrent requests")
	)
	flag.Parse()

	if *workloadManagerURL == "" {
		klog.Fatal("WORKLOAD_MANAGER_URL environment variable or --workload-manager-url flag is required")
	}

	server, err := router.NewServer(router.Config{
		Port:               *port,
		WorkloadManagerURL: *workloadManagerURL,
		EnableAuth:         *enableAuth,
		MaxConcurrent:      *maxConcurrent,
	})
	if err != nil {
		klog.Fatalf("Failed to create server: %v", err)
	}

	if err := server.Start(); err != nil {
		klog.Fatalf("Server error: %v", err)
	}
}

package router

import (
	"context"
	"fmt"
	"net/http"
	"time"

	"github.com/gin-gonic/gin"
	"github.com/volcano-sh/agentcube/pkg/store"
)

type Config struct {
	Port               int
	WorkloadManagerURL string
	EnableAuth         bool
	MaxConcurrent      int
}

type Server struct {
	config          Config
	router          *gin.Engine
	sessionManager  *SessionManager
	jwtManager      *JWTManager
	sharedTransport *http.Transport
}

func NewServer(config Config) (*Server, error) {
	gin.SetMode(gin.ReleaseMode)
	r := gin.New()
	r.Use(gin.Logger())
	r.Use(gin.Recovery())

	// Initialize session manager
	sessionManager, err := NewSessionManager(config.WorkloadManagerURL, store.Storage())
	if err != nil {
		return nil, fmt.Errorf("failed to create session manager: %w", err)
	}

	// Initialize JWT manager
	jwtManager, err := NewJWTManager()
	if err != nil {
		return nil, fmt.Errorf("failed to create JWT manager: %w", err)
	}

	s := &Server{
		config:          config,
		router:          r,
		sessionManager:  sessionManager,
		jwtManager:      jwtManager,
		sharedTransport: &http.Transport{
			MaxIdleConns:        100,
			MaxIdleConnsPerHost: 10,
			IdleConnTimeout:     90 * time.Second,
		},
	}

	s.setupRoutes()
	return s, nil
}

func (s *Server) setupRoutes() {
	// Health endpoints - no auth
	s.router.GET("/health/live", s.handleHealthLive)
	s.router.GET("/health/ready", s.handleHealthReady)

	// API routes with semaphore middleware
	v1 := s.router.Group("/v1")
	v1.Use(SemaphoreMiddleware(s.config.MaxConcurrent))

	// AgentRuntime routes
	v1.Any("/namespaces/:namespace/agent-runtimes/:name/invocations/*path", s.handleAgentRuntimeInvocation)

	// CodeInterpreter routes
	v1.Any("/namespaces/:namespace/code-interpreters/:name/invocations/*path", s.handleCodeInterpreterInvocation)
}

func (s *Server) Start() error {
	addr := fmt.Sprintf(":%d", s.config.Port)
	server := &http.Server{
		Addr:              addr,
		Handler:           s.router,
		ReadHeaderTimeout: 10 * time.Second,
	}
	return server.ListenAndServe()
}

package router

import (
	"context"
	"crypto/tls"
	"fmt"
	"io"
	"net/http"
	"net/http/httputil"
	"net/url"
	"strings"

	"github.com/gin-gonic/gin"
	"github.com/volcano-sh/agentcube/pkg/common/types"
	"github.com/volcano-sh/agentcube/pkg/store"
	"k8s.io/klog/v2"
)

type SessionManager struct {
	workloadManagerURL string
	store              store.Store
	httpClient         *http.Client
}

func NewSessionManager(workloadManagerURL string, s store.Store) (*SessionManager, error) {
	if workloadManagerURL == "" {
		return nil, fmt.Errorf("WORKLOAD_MANAGER_URL environment variable is not set")
	}

	return &SessionManager{
		workloadManagerURL: workloadManagerURL,
		store:              s,
		httpClient: &http.Client{
			Transport: &http.Transport{
				TLSClientConfig: &tls.Config{InsecureSkipVerify: true},
			},
		},
	}, nil
}

func (sm *SessionManager) GetSandboxBySession(ctx context.Context, sessionID string, kind string) (*types.SandboxInfo, error) {
	if sessionID == "" {
		// Create new sandbox
		return sm.createSandbox(ctx, kind)
	}

	// Load from store
	sandbox, err := sm.store.GetSandboxBySessionID(ctx, sessionID)
	if err != nil {
		if err == store.ErrNotFound {
			return nil, fmt.Errorf("session %s not found", sessionID)
		}
		return nil, err
	}

	return sandbox, nil
}

func (sm *SessionManager) createSandbox(ctx context.Context, kind string) (*types.SandboxInfo, error) {
	// Get auth token from service account
	token, err := getServiceAccountToken()
	if err != nil {
		klog.Warningf("Failed to get service account token: %v", err)
		token = ""
	}

	reqBody := types.CreateSandboxRequest{
		Kind: kind,
	}

	reqJSON, err := json.Marshal(reqBody)
	if err != nil {
		return nil, fmt.Errorf("failed to marshal request: %w", err)
	}

	url := fmt.Sprintf("%s/v1/sandbox", sm.workloadManagerURL)
	req, err := http.NewRequestWithContext(ctx, "POST", url, strings.NewReader(string(reqJSON)))
	if err != nil {
		return nil, fmt.Errorf("failed to create request: %w", err)
	}

	req.Header.Set("Content-Type", "application/json")
	if token != "" {
		req.Header.Set("Authorization", "Bearer "+token)
	}

	resp, err := sm.httpClient.Do(req)
	if err != nil {
		return nil, fmt.Errorf("failed to create sandbox: %w", err)
	}
	defer resp.Body.Close()

	if resp.StatusCode == http.StatusNotFound {
		return nil, fmt.Errorf("sandbox template not found")
	}

	if resp.StatusCode != http.StatusOK {
		body, _ := io.ReadAll(resp.Body)
		return nil, fmt.Errorf("failed to create sandbox: status=%d, body=%s", resp.StatusCode, string(body))
	}

	var createResp types.CreateSandboxResponse
	if err := json.NewDecoder(resp.Body).Decode(&createResp); err != nil {
		return nil, fmt.Errorf("failed to decode response: %w", err)
	}

	if createResp.SessionID == "" {
		return nil, fmt.Errorf("session ID is empty in response")
	}

	// Build SandboxInfo from response
	sandbox := &types.SandboxInfo{
		Kind:             kind,
		SandboxID:        createResp.SandboxID,
		SandboxNamespace: "default",
		Name:             createResp.SandboxName,
		SessionID:        createResp.SessionID,
		EntryPoints:      createResp.EntryPoints,
		Status:           "running",
	}

	return sandbox, nil
}

func getServiceAccountToken() (string, error) {
	data, err := os.ReadFile("/var/run/secrets/kubernetes.io/serviceaccount/token")
	if err != nil {
		return "", err
	}
	return string(data), nil
}

